PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(MAX(?audience) AS ?maxAttendance) WHERE {
  VALUES ?series {
    wd:Q3511260 wd:Q1188429 wd:Q14870261
  }
  ?game wdt:P361 ?series .
  ?game wdt:P1346 wd:Q504309 .
  ?game wdt:P1108 ?audience .
  FILTER isNumeric(?audience)
}
ORDER BY DESC(?audience)
LIMIT 1
